//! # Basin / separatrix gate — the diffusion analog of the argmax gate.
//!
//! Carrying the τ-bowl to image generation. A rectified-flow / diffusion sampler
//! evolves a latent `x_{t+1} = x_t + Δt·v(x_t, t)`. Just-in-time dequantization
//! of the velocity (masking coarse DiT/spectral weights up to higher precision)
//! perturbs each step by `δ_t`. For a *classifier* the decision is an argmax and
//! the gate is sup-norm ([`crate::tukey_bowl::gate`]); for an *image* there is no
//! argmax — the decision is **which basin of attraction (image mode)** the
//! trajectory lands in. The masked trajectory stays in the same mode iff its net
//! accumulated displacement error stays inside the distance to the **separatrix**
//! (the basin boundary).
//!
//! This is the runtime twin of
//! `Gnosis.BasinSeparatrixAdmissibility.net_displacement_within_basin`
//! (propext-only): if the per-step perturbation magnitudes sum to less than the
//! basin radius `R`, the net displacement is within `R`, so the trajectory cannot
//! cross the separatrix. Per-step magnitudes are exactly the energy-gate budgets
//! from `EnergyMarginBridgeAdmissibility`; this module accumulates them along the
//! trajectory and **misses (recomputes the exact velocity), never lies** the
//! moment admitting a masked step would risk a basin crossing.
//!
//! ## Where this plugs into the real carrier
//!
//! The Unsound FLUX carrier already runs a stride-11 (leech-turbo) E_8 spectral
//! residual path (`model_flux_txt2img`: `spectralDenoiseResidualQuantizer='e8'`,
//! `spectralDenoiseResidualStride=11`, the `…-r11` runs). [`BasinGate`] is the
//! admission layer for that path: feed it each step's spectral-residual L2 norm;
//! it returns `Admit` (carry the masked velocity) or `Miss` (recompute exact).
//! It is **not** wired into carrier execution here — flux-1-dev is admitted
//! dev-only, no real-knot run / cloud build / deploy — so this module proves and
//! demonstrates the mechanism on a synthetic double-well field instead.

#![allow(dead_code)]

use crate::tukey_bowl::{tukey_weight, Admission};

/// Accumulating basin gate. Holds the basin radius `R` (distance to the
/// separatrix) and the running sum of admitted per-step displacement errors.
#[derive(Clone, Copy, Debug)]
pub struct BasinGate {
    pub radius: f64,
    acc: f64,
}

impl BasinGate {
    /// New gate with basin radius `R` (the distance from the trajectory to the
    /// nearest separatrix; the budget the accumulated error may not exceed).
    pub fn new(radius: f64) -> Self {
        Self { radius, acc: 0.0 }
    }

    /// Offer a step whose masked-velocity displacement error magnitude is
    /// `delta_abs` (= `Δt·‖δ_t‖₂`). Admit iff the running total *stays* within
    /// the basin radius (`acc + delta_abs ≤ R`); then the accumulator advances.
    /// Otherwise **Miss** — the caller recomputes the exact velocity for this
    /// step and the accumulator does **not** advance (the exact step adds no
    /// error). This is `net_displacement_within_basin` enforced incrementally.
    #[inline]
    pub fn offer(&mut self, delta_abs: f64) -> Admission {
        if self.radius <= 0.0 {
            return Admission::Miss { tau: delta_abs };
        }
        if self.acc + delta_abs <= self.radius {
            self.acc += delta_abs;
            Admission::Admit {
                tau: delta_abs,
                // grade by remaining headroom: full influence with budget to
                // spare, redescending toward the separatrix.
                weight: tukey_weight(self.acc, self.radius),
            }
        } else {
            Admission::Miss { tau: delta_abs }
        }
    }

    /// Accumulated admitted displacement error so far.
    #[inline]
    pub fn accumulated(&self) -> f64 {
        self.acc
    }

    /// Remaining basin headroom before the separatrix.
    #[inline]
    pub fn headroom(&self) -> f64 {
        (self.radius - self.acc).max(0.0)
    }
}

// ── Synthetic double-well velocity field (the image-mode proxy) ──────────────

/// Double-well potential `U(x) = (x²−1)²`; drift `v(x) = −U'(x) = 4x − 4x³`.
/// Stable modes at `x = ±1` (the two "images"); unstable separatrix at `x = 0`.
/// A velocity perturbation near `x = 0` can flip which mode the trajectory falls
/// into — exactly the basin crossing the gate must forbid.
#[inline]
pub fn well_velocity(x: f64) -> f64 {
    4.0 * x - 4.0 * x * x * x
}

/// Quantize a velocity scalar to a coarse grid at `step` — the JIT-dequant
/// proxy: the masked (coarse) velocity. Near `x = 0` the true velocity is tiny,
/// so coarse quantization produces a large *relative* residual — the dangerous
/// regime, just like a diffusion step near a mode boundary.
#[inline]
fn quantize_vel(v: f64, step: f64) -> f64 {
    if step <= 0.0 {
        v
    } else {
        (v / step).round() * step
    }
}

/// Deterministic per-(trajectory, step) dither in `[-1, 1)`. Models the honest
/// fact that near a mode boundary the velocity is *below the quantization
/// resolution*, so the masked velocity's sign is set by quantization noise — it
/// is directionally **unreliable**, and can point toward the wrong basin. Pure
/// hash (SplitMix64), no rand dependency.
#[inline]
fn dither(seed: u64, t: usize) -> f64 {
    let mut z = seed.wrapping_add((t as u64).wrapping_mul(0x9E37_79B9_7F4A_7C15));
    z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
    z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
    z ^= z >> 31;
    let u = (z >> 11) as f64 / (1u64 << 53) as f64;
    (u - 0.5) * 2.0
}

/// Result of evolving one trajectory.
#[derive(Clone, Copy, Debug)]
pub struct Traj {
    /// Final latent position.
    pub x_final: f64,
    /// Mode it fell into: `+1` or `-1` (sign of the final position).
    pub mode: i32,
    /// Steps whose masked velocity was admitted (ran at coarse-code cost).
    pub admitted: usize,
    /// Steps that missed (exact velocity recomputed).
    pub missed: usize,
}

/// Evolve the true (exact-velocity) trajectory from `x0` for `n` steps of `dt`.
pub fn evolve_true(x0: f64, dt: f64, n: usize) -> Traj {
    let mut x = x0;
    for _ in 0..n {
        x += dt * well_velocity(x);
    }
    Traj {
        x_final: x,
        mode: if x >= 0.0 { 1 } else { -1 },
        admitted: 0,
        missed: 0,
    }
}

/// Evolve a JIT-dequantized trajectory from `x0`. Each step's velocity is masked
/// (quantized at `vel_step`, plus dither modelling sub-resolution sign
/// unreliability). When `gated`, the **basin gate** admits the masked step only
/// if it does **not** carry the latent across the separatrix (`x = 0`); a step
/// that would cross **misses** and recomputes the exact velocity (which, on each
/// side, always flows *away* from the separatrix — never crosses). When ungated,
/// every step carries the masked velocity — the baseline that can flip modes.
///
/// The per-step crossing check is the *operational* enforcement of
/// `Gnosis.BasinSeparatrixAdmissibility`: it guarantees no separatrix crossing
/// even in the locally-expansive region near the boundary, where the additive
/// accumulated-budget bound ([`BasinGate::offer`]) — exact under non-expansive
/// flow — would need a tighter radius. Both refuse to lie; the crossing check is
/// simply the strictest honest budget (zero headroom at the boundary).
pub fn evolve_masked(x0: f64, dt: f64, n: usize, vel_step: f64, gated: bool, seed: u64) -> Traj {
    let mut x = x0;
    let dith_amp = vel_step; // dither at the quantization scale (resolution floor)
    let mut admitted = 0usize;
    let mut missed = 0usize;
    for t in 0..n {
        let v_true = well_velocity(x);
        let v_mask = quantize_vel(v_true + dith_amp * dither(seed, t), vel_step);
        let v_used = if gated {
            let new_x = x + dt * v_mask;
            let crosses = (x > 0.0 && new_x <= 0.0) || (x < 0.0 && new_x >= 0.0);
            if crosses {
                missed += 1;
                v_true // recompute exact — flows away from the separatrix, safe
            } else {
                admitted += 1;
                v_mask
            }
        } else {
            admitted += 1;
            v_mask
        };
        x += dt * v_used;
    }
    Traj {
        x_final: x,
        mode: if x >= 0.0 { 1 } else { -1 },
        admitted,
        missed,
    }
}

/// Scoreboard over a sweep of initial conditions: how often the masked
/// trajectory lands in the SAME mode as the true trajectory (mode preservation),
/// and the masking accept rate, with vs without the basin gate.
#[derive(Clone, Copy, Debug, Default)]
pub struct BasinReport {
    pub trajectories: usize,
    /// Trajectories whose masked mode == true mode.
    pub mode_preserved: usize,
    /// Trajectories that flipped to the wrong mode (the failure the gate forbids).
    pub mode_flipped: usize,
    /// Mean fraction of steps admitted (masked at coarse cost).
    pub accept_rate: f64,
}

impl BasinReport {
    pub fn preservation_rate(&self) -> f64 {
        if self.trajectories == 0 {
            0.0
        } else {
            self.mode_preserved as f64 / self.trajectories as f64
        }
    }
}

/// Run the mode-preservation experiment over initial conditions in `[-x_max,
/// x_max]` (densely sampling near the separatrix, the hard regime).
pub fn run_basin_experiment(
    x_max: f64,
    n_init: usize,
    dt: f64,
    n_steps: usize,
    vel_step: f64,
    gated: bool,
) -> BasinReport {
    let mut rep = BasinReport::default();
    let mut acc_admit = 0.0f64;
    for i in 0..n_init {
        // initial conditions spread across the separatrix, excluding exact 0.
        let frac = (i as f64 + 0.5) / n_init as f64; // (0,1)
        let x0 = -x_max + 2.0 * x_max * frac;
        if x0.abs() < 1e-6 {
            continue;
        }
        let truth = evolve_true(x0, dt, n_steps);
        // per-trajectory dither seed (deterministic, varies by initial condition)
        let seed = 0xBA51_0000u64 ^ (i as u64).wrapping_mul(0x9E37_79B9);
        let masked = evolve_masked(x0, dt, n_steps, vel_step, gated, seed);
        rep.trajectories += 1;
        if masked.mode == truth.mode {
            rep.mode_preserved += 1;
        } else {
            rep.mode_flipped += 1;
        }
        let steps = (masked.admitted + masked.missed).max(1);
        acc_admit += masked.admitted as f64 / steps as f64;
    }
    rep.accept_rate = if rep.trajectories > 0 {
        acc_admit / rep.trajectories as f64
    } else {
        0.0
    };
    rep
}

// ════════════════════════════════════════════════════════════════════════
//  REAL-VELOCITY GATE — the basin gate wired to the actual FLUX flow-match
//  velocity field (not the synthetic double well).
// ════════════════════════════════════════════════════════════════════════
//
//  The synthetic double-well above proves the *mechanism*. This section is the
//  runtime twin that the real FLUX denoise loop (`model_flux_txt2img::
//  build_flux_real_image`) calls per step. At step `t` it is handed:
//
//    * the EXACT velocity `v_exact = DiT.velocity(x_t, …)` (ground truth), and
//    * a CHEAP/masked velocity `v_cheap` (a speculative draft — carry-forward of
//      the previous step's velocity, or a coarse-code velocity).
//
//  It measures the per-step displacement residual `‖Δt·(v_exact − v_cheap)‖₂`,
//  offers it to the accumulating [`BasinGate`], and returns whether the cheap
//  draft is ADMITTED (carry `v_cheap`, certified within the basin budget) or a
//  MISS (carry `v_exact`). The accumulator can never exceed the basin radius, so
//  the gated trajectory's net displacement from the exact trajectory is provably
//  bounded by `R` — it cannot cross a separatrix the exact run stays clear of.
//
//  This replaces basin_gate's synthetic well with the REAL velocity, satisfying
//  increment (1) of the Unsound-FLUX → real-runtime evolution.

/// L2 norm of `a − b` (the displacement residual magnitude).
#[inline]
pub fn l2_diff(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());
    let mut s = 0.0f64;
    for i in 0..a.len() {
        let e = (a[i] - b[i]) as f64;
        s += e * e;
    }
    s.sqrt()
}

/// Per-step decision of the real-velocity gate.
#[derive(Clone, Copy, Debug, PartialEq)]
pub enum StepDecision {
    /// The cheap/masked velocity is certified within the remaining basin budget;
    /// carry it (the step ran at draft cost). `residual` = `Δt·‖v_exact−v_cheap‖₂`.
    AdmitCheap { residual: f64, headroom_after: f64 },
    /// Admitting the cheap step would risk a basin crossing; carry the exact
    /// velocity instead (miss, not lie). The accumulator does not advance.
    MissExact { residual: f64 },
}

impl StepDecision {
    #[inline]
    pub fn admitted(&self) -> bool {
        matches!(self, StepDecision::AdmitCheap { .. })
    }
    #[inline]
    pub fn residual(&self) -> f64 {
        match *self {
            StepDecision::AdmitCheap { residual, .. } | StepDecision::MissExact { residual } => {
                residual
            }
        }
    }
}

/// Driver that the real denoise loop folds the per-step gate through. Holds the
/// accumulating [`BasinGate`] plus a running scoreboard so the loop only has to
/// call [`offer_step`](RealVelocityGate::offer_step) and read [`report`] at the
/// end.
#[derive(Clone, Debug)]
pub struct RealVelocityGate {
    gate: BasinGate,
    admitted: usize,
    missed: usize,
    /// Sum of the residuals that were actually admitted (advanced the budget).
    admitted_residual_sum: f64,
    /// Worst single admitted residual (must be ≤ remaining headroom at the time).
    max_admitted_residual: f64,
    /// Sum of all offered residuals (admitted + would-be), for reporting the
    /// "free" cheap-step error magnitude even when the gate refuses it.
    offered_residual_sum: f64,
}

impl RealVelocityGate {
    /// New driver. `basin_radius` is the certified distance budget the
    /// accumulated cheap-step error may not exceed over the whole trajectory.
    pub fn new(basin_radius: f64) -> Self {
        Self {
            gate: BasinGate::new(basin_radius),
            admitted: 0,
            missed: 0,
            admitted_residual_sum: 0.0,
            max_admitted_residual: 0.0,
            offered_residual_sum: 0.0,
        }
    }

    /// Offer one step. `dt` is the Euler step size `σ_{t+1}−σ_t` (negative in the
    /// flow-match schedule; its magnitude scales the displacement). `v_exact` and
    /// `v_cheap` are the exact and draft velocities for this step. Returns the
    /// decision; the caller carries `v_cheap` on `AdmitCheap`, `v_exact` on
    /// `MissExact`.
    pub fn offer_step(&mut self, dt: f32, v_exact: &[f32], v_cheap: &[f32]) -> StepDecision {
        // Δt·‖v_exact − v_cheap‖₂ — the latent displacement error this cheap
        // step would inject (exactly the per-step magnitude `EnergyMarginBridge`
        // bounds, here in the latent's own L2 metric).
        let residual = (dt.abs() as f64) * l2_diff(v_exact, v_cheap);
        self.offered_residual_sum += residual;
        match self.gate.offer(residual) {
            Admission::Admit { .. } => {
                self.admitted += 1;
                self.admitted_residual_sum += residual;
                if residual > self.max_admitted_residual {
                    self.max_admitted_residual = residual;
                }
                StepDecision::AdmitCheap {
                    residual,
                    headroom_after: self.gate.headroom(),
                }
            }
            Admission::Miss { .. } => {
                self.missed += 1;
                StepDecision::MissExact { residual }
            }
        }
    }

    /// Final scoreboard.
    pub fn report(&self) -> RealVelocityGateReport {
        let steps = self.admitted + self.missed;
        RealVelocityGateReport {
            steps,
            admitted: self.admitted,
            missed: self.missed,
            basin_radius: self.gate.radius,
            accumulated: self.gate.accumulated(),
            headroom: self.gate.headroom(),
            admit_rate: if steps == 0 {
                0.0
            } else {
                self.admitted as f64 / steps as f64
            },
            max_admitted_residual: self.max_admitted_residual,
            offered_residual_sum: self.offered_residual_sum,
        }
    }
}

/// Aggregate result of running the real-velocity gate over a denoise trajectory.
#[derive(Clone, Copy, Debug, Default)]
pub struct RealVelocityGateReport {
    pub steps: usize,
    pub admitted: usize,
    pub missed: usize,
    pub basin_radius: f64,
    /// Accumulated admitted displacement error (≤ `basin_radius`, always).
    pub accumulated: f64,
    /// Remaining headroom before the certified basin boundary.
    pub headroom: f64,
    /// Fraction of steps run at cheap-draft cost — the speedup proxy.
    pub admit_rate: f64,
    /// Worst admitted per-step residual.
    pub max_admitted_residual: f64,
    /// Sum of all offered residuals (admitted + refused).
    pub offered_residual_sum: f64,
}

impl RealVelocityGateReport {
    /// The certified safety invariant: the accumulated error never exceeded the
    /// basin radius (the runtime witness of `net_displacement_within_basin`).
    #[inline]
    pub fn within_basin(&self) -> bool {
        self.accumulated <= self.basin_radius + 1e-9
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn double_well_flows_to_the_nearest_mode() {
        // exact dynamics: x0>0 → +1, x0<0 → −1.
        assert_eq!(evolve_true(0.2, 0.05, 400).mode, 1);
        assert_eq!(evolve_true(-0.2, 0.05, 400).mode, -1);
        assert!((evolve_true(0.2, 0.05, 400).x_final - 1.0).abs() < 0.05);
    }

    #[test]
    fn basin_gate_never_exceeds_radius() {
        let mut g = BasinGate::new(1.0);
        assert!(matches!(g.offer(0.4), Admission::Admit { .. }));
        assert!(matches!(g.offer(0.5), Admission::Admit { .. })); // acc=0.9 ≤ 1.0
        assert!(matches!(g.offer(0.2), Admission::Miss { .. })); // 1.1 > 1.0 → miss
        assert!(g.accumulated() <= 1.0, "gate must never exceed the basin radius");
        // the missed step did not advance the accumulator
        assert!((g.accumulated() - 0.9).abs() < 1e-9);
    }

    /// THE HEADLINE: the basin gate certifies mode preservation. Ungated masking
    /// flips some near-separatrix trajectories into the WRONG image mode; the
    /// gated path preserves EVERY mode (miss-not-lie) while still masking most
    /// steps. Coarse velocity step so the residual near x=0 is dangerous.
    #[test]
    fn basin_gate_preserves_image_mode() {
        // start near the separatrix (the hard regime) so masked steps genuinely
        // threaten basin crossings.
        let (x_max, n_init, dt, n_steps, vel_step) = (0.1f64, 400, 0.05, 400, 0.6);

        let ungated = run_basin_experiment(x_max, n_init, dt, n_steps, vel_step, false);
        let gated = run_basin_experiment(x_max, n_init, dt, n_steps, vel_step, true);

        println!(
            "\n[BASIN GATE | double-well, vel_step={vel_step}]\n  \
             UNGATED: mode-preserved {}/{} ({:.1}%)  flipped {}  accept {:.1}%\n  \
             GATED:   mode-preserved {}/{} ({:.1}%)  flipped {}  accept {:.1}%",
            ungated.mode_preserved, ungated.trajectories, 100.0 * ungated.preservation_rate(),
            ungated.mode_flipped, 100.0 * ungated.accept_rate,
            gated.mode_preserved, gated.trajectories, 100.0 * gated.preservation_rate(),
            gated.mode_flipped, 100.0 * gated.accept_rate,
        );

        // The gate must let SOME masking through (it is not just "recompute all").
        assert!(gated.accept_rate > 0.0, "gate must admit some masked steps");
        // The gate must NEVER let a trajectory cross into the wrong mode.
        assert_eq!(gated.mode_flipped, 0, "basin gate must preserve every image mode");
        // And it must be doing real work: ungated masking DOES flip modes, so the
        // gate is preventing genuine failures, not guarding a non-problem.
        assert!(
            ungated.mode_flipped > 0,
            "the coarse-velocity regime must actually threaten mode flips for the gate to matter"
        );
        // The gate strictly improves preservation over ungated.
        assert!(gated.preservation_rate() > ungated.preservation_rate());
    }

    // ── real-velocity gate (the FLUX denoise-loop twin) ─────────────────────

    #[test]
    fn real_velocity_gate_admits_within_budget_and_misses_when_full() {
        // A real-shaped residual: two velocity vectors over a latent token block.
        let v_exact = vec![1.0f32, 2.0, 3.0, 4.0];
        // cheap draft differs by 0.1 per coord ⇒ ‖diff‖₂ = 0.2; dt magnitude 0.5
        // ⇒ residual = 0.1 per step.
        let v_cheap: Vec<f32> = v_exact.iter().map(|x| x + 0.1).collect();
        let dt = -0.5f32;

        // Radius 0.25 ⇒ two cheap steps (0.1+0.1=0.2) fit, the third (0.3>0.25)
        // must miss → carry exact.
        let mut g = RealVelocityGate::new(0.25);
        assert!(g.offer_step(dt, &v_exact, &v_cheap).admitted(), "step 0 fits");
        assert!(g.offer_step(dt, &v_exact, &v_cheap).admitted(), "step 1 fits");
        assert!(
            !g.offer_step(dt, &v_exact, &v_cheap).admitted(),
            "step 2 would exceed the basin radius → miss, not lie"
        );
        let rep = g.report();
        assert_eq!(rep.admitted, 2);
        assert_eq!(rep.missed, 1);
        assert!(rep.within_basin(), "accumulated error must stay inside the basin");
        assert!(rep.accumulated <= rep.basin_radius + 1e-9);
        // residual magnitude is exactly 0.1 per step (0.5·0.2).
        assert!((rep.max_admitted_residual - 0.1).abs() < 1e-6);
        assert!((rep.admit_rate - 2.0 / 3.0).abs() < 1e-9);
    }

    #[test]
    fn real_velocity_gate_admits_every_exact_match() {
        // If the cheap draft equals the exact velocity, residual is 0 ⇒ every
        // step admits for free (the trivial-safe regime).
        let v = vec![0.3f32, -0.7, 1.1, 0.0, -2.0];
        let mut g = RealVelocityGate::new(0.01);
        for _ in 0..8 {
            let d = g.offer_step(-1.0, &v, &v);
            assert!(d.admitted());
            assert_eq!(d.residual(), 0.0);
        }
        let rep = g.report();
        assert_eq!(rep.admitted, 8);
        assert_eq!(rep.missed, 0);
        assert_eq!(rep.accumulated, 0.0);
    }

    #[test]
    fn zero_radius_basin_refuses_all_cheap_steps() {
        // No budget ⇒ fail-closed: every step takes the exact velocity.
        let v_exact = vec![1.0f32, 0.0];
        let v_cheap = vec![1.5f32, 0.5];
        let mut g = RealVelocityGate::new(0.0);
        for _ in 0..4 {
            assert!(!g.offer_step(-0.5, &v_exact, &v_cheap).admitted());
        }
        assert_eq!(g.report().admitted, 0);
    }
}
